// Kept as `base + base * rate` (rather than `base * (1 + rate)`) so the
// reducer accumulates base and insurance separately — avoids 25 * 1.1 + 25 * 1.1
// producing 60.00000000000001 for the two-rune case.
const itemsTotal = items.reduce((sum, item) => {
  const base = BASE_PREMIUMS[item.type];
  return sum + base + base * FIRST_INSURANCE_RATE;
}, 0);
